import React, { useEffect, useRef, useState } from "react";

const FONT_B64_PLACEHOLDER = "";

const CSS = `
  @font-face {
    font-family: 'NTFGrand';
    src: url('data:font/otf;base64,${FONT_B64_PLACEHOLDER}') format('opentype');
    font-weight: 900;
    font-style: italic;
    font-display: block;
  }

  .ci-root {
    position: fixed; inset: 0; z-index: 9999;
    background: #000;
    overflow-y: scroll; overflow-x: hidden;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: none;
  }
  .ci-root::-webkit-scrollbar { display: none; }
  .ci-track { height: 600vh; position: relative; }
  .ci-sticky {
    position: sticky; top: 0;
    height: 100vh; width: 100%;
    display: flex; align-items: center; justify-content: center;
    overflow: hidden;
    perspective: 1200px;
  }

  /* BG */
  .ci-bg {
    position: absolute; inset: 0; z-index: 0;
    background-image: url('https://i.ibb.co/jv4jBQt4/BG-FIXO.png');
    background-size: cover; background-position: center;
    will-change: transform;
    transform-origin: center center;
  }
  .ci-bg-overlay {
    position: absolute; inset: 0; z-index: 1;
    background: rgba(0,0,0,0.15);
    will-change: opacity;
  }
  .ci-vignette {
    position: absolute; inset: 0; z-index: 2; pointer-events: none;
    background: radial-gradient(ellipse at center, transparent 30%, rgba(0,0,0,0.75) 100%);
  }
  .ci-grain {
    position: absolute; inset: 0; pointer-events: none; z-index: 3;
    opacity: 0.045; mix-blend-mode: overlay;
    background: url('data:image/svg+xml;utf8,<svg viewBox="0 0 200 200" xmlns="http://www.w3.org/2000/svg"><filter id="n"><feTurbulence type="fractalNoise" baseFrequency="0.85" numOctaves="4" stitchTiles="stitch"/></filter><rect width="100%" height="100%" filter="url(%23n)"/></svg>');
  }

  /* Scanlines */
  .ci-scanlines {
    position: absolute; inset: 0; z-index: 4; pointer-events: none;
    opacity: 0.025;
    background: repeating-linear-gradient(
      0deg,
      transparent,
      transparent 2px,
      rgba(255,255,255,0.03) 2px,
      rgba(255,255,255,0.03) 4px
    );
  }

  /* Horizontal light streak */
  .ci-streak {
    position: absolute; z-index: 5; pointer-events: none;
    top: 50%; left: -100%;
    width: 60%; height: 1px;
    background: linear-gradient(90deg, transparent, rgba(255,90,0,0.4), transparent);
    animation: ci-streak-move 6s ease-in-out infinite 2.5s;
    will-change: transform;
  }
  @keyframes ci-streak-move {
    0%   { transform: translateX(0) translateY(-50%); opacity: 0; }
    10%  { opacity: 1; }
    80%  { opacity: 0.6; }
    100% { transform: translateX(350%) translateY(-50%); opacity: 0; }
  }

  /* Corner accents */
  .ci-corner {
    position: absolute; z-index: 6; pointer-events: none;
    width: 40px; height: 40px;
    opacity: 0;
    animation: ci-fadeup 0.5s ease 1.8s forwards;
  }
  .ci-corner--tl { top: 28px; left: 28px; border-top: 1.5px solid rgba(255,90,0,0.5); border-left: 1.5px solid rgba(255,90,0,0.5); }
  .ci-corner--tr { top: 28px; right: 28px; border-top: 1.5px solid rgba(255,90,0,0.5); border-right: 1.5px solid rgba(255,90,0,0.5); }
  .ci-corner--bl { bottom: 28px; left: 28px; border-bottom: 1.5px solid rgba(255,90,0,0.5); border-left: 1.5px solid rgba(255,90,0,0.5); }
  .ci-corner--br { bottom: 28px; right: 28px; border-bottom: 1.5px solid rgba(255,90,0,0.5); border-right: 1.5px solid rgba(255,90,0,0.5); }

  /* HERO */
  .ci-hero-wrap {
    position: absolute; inset: 0; z-index: 10;
    display: flex; flex-direction: column;
    align-items: center; justify-content: center;
    text-align: center; padding: 0 24px;
    will-change: transform, opacity, filter;
    transform-style: preserve-3d;
  }
  .ci-headline {
    display: flex; flex-direction: column;
    align-items: center; gap: 0;
  }

  .ci-line1 {
    font-family: 'NTFGrand', sans-serif;
    font-weight: 900; font-style: italic;
    font-size: clamp(50px, 10vw, 116px);
    line-height: 0.9; margin: 0;
    white-space: nowrap;
    will-change: transform, opacity, filter;
  }
  .ci-line2 {
    font-family: 'NTFGrand', sans-serif;
    font-weight: 900; font-style: italic;
    font-size: clamp(50px, 10vw, 116px);
    line-height: 0.9; margin: 0;
    color: #fff;
    white-space: nowrap;
    opacity: 0;
    transform: translateY(70px) scale(0.88);
    filter: blur(18px);
    animation: ci-slam 0.85s cubic-bezier(0.16,1,0.3,1) 0.7s forwards;
    will-change: transform, opacity, filter;
  }
  @keyframes ci-slam {
    to { opacity: 1; transform: translateY(0) scale(1); filter: blur(0); }
  }

  /* Per-character entrance for line1 */
  .ci-char {
    display: inline-block;
    opacity: 0;
    transform: translateY(60px) scaleY(1.3);
    filter: blur(12px);
    animation: ci-char-in 0.55s cubic-bezier(0.16,1,0.3,1) forwards;
    will-change: transform, opacity, filter;
  }
  @keyframes ci-char-in {
    to { opacity: 1; transform: translateY(0) scaleY(1); filter: blur(0); }
  }
  /* Space between words */
  .ci-char-space { display: inline-block; width: 0.28em; }

  .ci-word-navy { color: #1a2a5e; }
  .ci-word-white { color: #ffffff; }

  .ci-line1-inner {
    display: inline-block;
    animation: ci-glitch 7s infinite 2s;
  }
  @keyframes ci-glitch {
    0%,92%,100% { transform:none; filter:none; }
    93% { transform:translate(-3px,0) skewX(8deg); filter:hue-rotate(160deg) saturate(2); opacity:.8; }
    94% { transform:translate(3px,0) skewX(-5deg); opacity:1; }
    95% { transform:none; filter:none; }
    97% { transform:translate(-1px,1px); opacity:.9; }
    98% { transform:none; opacity:1; }
  }

  .ci-line2-inner {
    display: inline-block;
    animation: ci-chroma 8s infinite 3s;
  }
  @keyframes ci-chroma {
    0%,88%,100% { text-shadow:none; }
    89% { text-shadow:-4px 0 rgba(255,30,80,0.8), 4px 0 rgba(0,200,255,0.8); }
    90% { text-shadow:2px 0 rgba(255,30,80,0.5),-2px 0 rgba(0,200,255,0.5); }
    91% { text-shadow:none; }
    94% { text-shadow:-2px 0 rgba(255,30,80,0.4), 2px 0 rgba(0,200,255,0.4); }
    95% { text-shadow:none; }
  }

  /* Divider */
  .ci-divider {
    display: flex; align-items: center;
    margin-top: 20px;
    width: clamp(300px, 58vw, 700px);
    height: 3px; gap: 0;
    opacity: 0;
    animation: ci-fadeup 0.5s ease 1.1s forwards;
    position: relative;
  }
  .ci-div-white { flex: 3; height: 100%; background: #fff; border-radius: 2px 0 0 2px; position: relative; overflow: hidden; }
  .ci-div-white::after {
    content: '';
    position: absolute; top: 0; left: -100%; width: 40%; height: 100%;
    background: linear-gradient(90deg, transparent, rgba(255,90,0,0.8), transparent);
    animation: ci-shimmer 3s ease-in-out infinite 2s;
  }
  @keyframes ci-shimmer { to { left: 200%; } }
  .ci-div-navy  { flex: 1.2; height: 100%; background: #1a2a5e; border-radius: 0 2px 2px 0; }

  /* Tagline below divider */
  .ci-tagline {
    font-family: 'NTFGrand', sans-serif;
    font-size: clamp(10px, 1.4vw, 14px);
    letter-spacing: 8px;
    text-transform: uppercase;
    color: rgba(255,255,255,0.22);
    font-style: italic;
    margin-top: 18px;
    opacity: 0;
    animation: ci-fadeup 0.5s ease 1.4s forwards;
    white-space: nowrap;
  }

  /* Scroll hint */
  .ci-hint {
    position: absolute; bottom: 40px;
    display: flex; flex-direction: column; align-items: center; gap: 12px;
    z-index: 20; opacity: 0;
    animation: ci-fadeup 0.5s ease 2s forwards;
  }
  .ci-hint span {
    font-family: 'NTFGrand', sans-serif;
    font-size: 11px; letter-spacing: 6px;
    text-transform: uppercase; color: rgba(255,255,255,0.28);
    font-style: italic; font-weight: 700;
  }
  .ci-hint-arrow {
    width: 18px; height: 18px;
    border-right: 1.5px solid rgba(255,255,255,0.4);
    border-bottom: 1.5px solid rgba(255,255,255,0.4);
    transform: rotate(45deg);
    animation: ci-bounce 1.4s ease-in-out infinite;
  }
  .ci-hint-line {
    width: 1px; height: 32px;
    background: linear-gradient(to bottom, rgba(255,90,0,0.6), transparent);
    animation: ci-pulse-line 1.4s ease-in-out infinite;
  }
  @keyframes ci-pulse-line {
    0%,100% { opacity: 0.3; transform: scaleY(0.7); }
    50% { opacity: 1; transform: scaleY(1); }
  }
  @keyframes ci-bounce {
    0%,100% { transform:rotate(45deg) translate(0,0); opacity:.4; }
    50%      { transform:rotate(45deg) translate(5px,5px); opacity:1; }
  }
  @keyframes ci-fadeup { to { opacity:1; } }

  /* CARD */
  .ci-card {
    position: absolute; z-index: 20;
    background: #FF5A00;
    box-shadow:
      0 80px 160px -20px rgba(0,0,0,0.9),
      0 0 0 1px rgba(255,90,0,0.3),
      inset 0 1px 0 rgba(255,255,255,0.1);
    border-radius: 28px;
    width: 92vw; height: 92vh;
    display: flex; align-items: center; justify-content: center;
    overflow: hidden;
    will-change: transform, border-radius, width, height;
    pointer-events: none;
  }

  /* Card mesh gradient (orange bg — fades out when iframe loads) */
  .ci-card-mesh {
    position: absolute; inset: 0;
    background:
      radial-gradient(ellipse at 20% 30%, rgba(255,120,40,0.5) 0%, transparent 55%),
      radial-gradient(ellipse at 80% 70%, rgba(200,40,0,0.4) 0%, transparent 50%),
      radial-gradient(ellipse at 50% 50%, rgba(255,90,0,1) 0%, rgba(220,50,0,1) 100%);
    z-index: 0;
    transition: opacity 0.6s ease;
  }
  .ci-card-mesh.iframe-loaded { opacity: 0; }

  .ci-card-noise {
    position: absolute; inset: 0; z-index: 2; pointer-events: none;
    opacity: 0.06;
    background: url('data:image/svg+xml;utf8,<svg viewBox="0 0 200 200" xmlns="http://www.w3.org/2000/svg"><filter id="n"><feTurbulence type="fractalNoise" baseFrequency="0.75" numOctaves="4" stitchTiles="stitch"/></filter><rect width="100%" height="100%" filter="url(%23n)"/></svg>');
    transition: opacity 0.6s ease;
  }
  .ci-card-noise.iframe-loaded { opacity: 0; }

  /* Card top/accent accents */
  .ci-card-top {
    position: absolute; top: 0; left: 0; right: 0; height: 3px; z-index: 6;
    background: linear-gradient(90deg, transparent 0%, rgba(255,255,255,0.3) 30%, rgba(255,255,255,0.5) 50%, rgba(255,255,255,0.3) 70%, transparent 100%);
    transition: opacity 0.6s ease;
  }
  .ci-card-top.iframe-loaded { opacity: 0; }
  .ci-card-accent {
    position: absolute; bottom: 0; left: 0; right: 0; height: 4px; z-index: 6;
    background: linear-gradient(90deg, transparent, #1a2a5e 40%, #1a2a5e 60%, transparent);
    transition: opacity 0.6s ease;
  }
  .ci-card-accent.iframe-loaded { opacity: 0; }

  /* Spinner shown while iframe is loading */
  .ci-card-spinner {
    position: absolute; inset: 0; z-index: 8;
    display: flex; align-items: center; justify-content: center;
    pointer-events: none;
    transition: opacity 0.4s ease;
  }
  .ci-card-spinner.iframe-loaded { opacity: 0; pointer-events: none; }
  .ci-spinner-ring {
    width: 48px; height: 48px;
    border: 3px solid rgba(255,255,255,0.15);
    border-top-color: rgba(255,255,255,0.7);
    border-radius: 50%;
    animation: ci-spin 0.9s linear infinite;
  }
  @keyframes ci-spin { to { transform: rotate(360deg); } }

  /* IFRAME inside card */
  .ci-card-iframe-wrap {
    position: absolute; inset: 0; z-index: 3;
    overflow: hidden;
    border-radius: inherit; /* mirrors card border-radius */
    opacity: 0;
    transition: opacity 0.5s ease;
  }
  .ci-card-iframe-wrap.iframe-loaded { opacity: 1; }

  .ci-card-iframe {
    width: 100%; height: 100%;
    border: none;
    display: block;
    /* Start zoomed in + blurred — "the site is out there" */
    transform-origin: center center;
    transform: scale(1.15);
    filter: blur(6px);
    will-change: transform, filter;
    /* pointer-events off until fullscreen */
    pointer-events: none;
    transition: transform 0s linear, filter 0s linear;
  }
  /* When fullscreen snap is done, iframe should be at scale(1) blur(0) — set via JS */

  /* SKIP */
  .ci-skip {
    position: fixed; bottom: 24px; right: 28px; z-index: 10001;
    font-family: 'NTFGrand', sans-serif;
    font-size: 11px; letter-spacing: 5px; text-transform: uppercase;
    font-weight: 700; font-style: italic;
    color: rgba(255,255,255,0.18); background: none; border: none; cursor: pointer;
    transition: color 0.2s, letter-spacing 0.3s; opacity: 0; padding: 8px 0;
    animation: ci-fadeup 0.4s ease 2.6s forwards;
  }
  .ci-skip:hover { color: rgba(255,255,255,0.75); letter-spacing: 7px; }
`;

interface Props { onComplete: () => void; }

export function CinematicIntro({ onComplete }: Props) {
  const rootRef    = useRef<HTMLDivElement>(null);
  const bgRef      = useRef<HTMLDivElement>(null);
  const overlayRef = useRef<HTMLDivElement>(null);
  const heroRef    = useRef<HTMLDivElement>(null);
  const cardRef    = useRef<HTMLDivElement>(null);
  const meshRef    = useRef<HTMLDivElement>(null);
  const noiseRef   = useRef<HTMLDivElement>(null);
  const topRef     = useRef<HTMLDivElement>(null);
  const accentRef  = useRef<HTMLDivElement>(null);
  const spinnerRef = useRef<HTMLDivElement>(null);
  const iframeWrapRef = useRef<HTMLDivElement>(null);
  const iframeRef  = useRef<HTMLIFrameElement>(null);
  const doneRef           = useRef(false);
  const rafRef            = useRef<number>(0);
  const snapFullscreenRef = useRef(false);
  const iframeLoadedRef   = useRef(false);

  // Current card "progress" for iframe zoom/blur interpolation
  const p2Ref = useRef(0);

  const [iframeUrl] = useState(() =>
    typeof window !== 'undefined' ? window.location.href : '/'
  );

  // Mark iframe as loaded: fade orange bg away, fade iframe in
  const handleIframeLoad = () => {
    iframeLoadedRef.current = true;
    meshRef.current?.classList.add('iframe-loaded');
    noiseRef.current?.classList.add('iframe-loaded');
    topRef.current?.classList.add('iframe-loaded');
    accentRef.current?.classList.add('iframe-loaded');
    spinnerRef.current?.classList.add('iframe-loaded');
    if (iframeWrapRef.current) {
      iframeWrapRef.current.classList.add('iframe-loaded');
    }
  };

  const triggerExit = () => {
    if (doneRef.current) return;
    doneRef.current = true;

    // Enable pointer events on iframe before unmounting so the transition is seamless
    if (iframeRef.current) {
      iframeRef.current.style.pointerEvents = 'auto';
      // Ensure scale/blur are at 1/0 for clean transition
      iframeRef.current.style.transform = 'scale(1)';
      iframeRef.current.style.filter = 'blur(0px)';
    }

    // Call onComplete — component unmounts, site below is already visible via iframe
    onComplete();
  };

  useEffect(() => {
    const root    = rootRef.current;
    const bg      = bgRef.current;
    const overlay = overlayRef.current;
    const hero    = heroRef.current;
    const card    = cardRef.current;
    const iframe  = iframeRef.current;
    if (!root || !bg || !hero || !card) return;

    const vh = window.innerHeight;
    card.style.transform = `translateY(${vh + 400}px)`;

    const snapToFullscreen = () => {
      if (snapFullscreenRef.current || doneRef.current) return;
      snapFullscreenRef.current = true;

      // Animate card to fullscreen
      card.style.transition = 'width 0.45s cubic-bezier(0.16,1,0.3,1), height 0.45s cubic-bezier(0.16,1,0.3,1), border-radius 0.45s cubic-bezier(0.16,1,0.3,1), transform 0.45s cubic-bezier(0.16,1,0.3,1)';
      card.style.width        = '100vw';
      card.style.height       = '100vh';
      card.style.borderRadius = '0px';
      card.style.transform    = 'translateY(0px) rotateX(0deg)';

      // Also animate iframe to scale(1) blur(0) in sync
      if (iframe) {
        iframe.style.transition = 'transform 0.45s cubic-bezier(0.16,1,0.3,1), filter 0.45s cubic-bezier(0.16,1,0.3,1)';
        iframe.style.transform = 'scale(1)';
        iframe.style.filter = 'blur(0px)';
      }

      // Sync border-radius on iframe wrap with card
      if (iframeWrapRef.current) {
        iframeWrapRef.current.style.transition = 'border-radius 0.45s cubic-bezier(0.16,1,0.3,1), opacity 0.5s ease';
        iframeWrapRef.current.style.borderRadius = '0px';
      }

      // After animation, call onComplete
      setTimeout(triggerExit, 500);
    };

    const onScroll = () => {
      cancelAnimationFrame(rafRef.current);
      rafRef.current = requestAnimationFrame(() => {
        if (doneRef.current || snapFullscreenRef.current) return;
        const sy    = root.scrollTop;
        const total = root.scrollHeight - vh;
        const p     = Math.min(sy / total, 1);

        // Phase 1 (0→0.4): hero out + bg zoom
        const p1 = Math.min(p / 0.4, 1);
        const e1 = p1 * p1 * p1;
        hero.style.transform = `perspective(1200px) translateY(${-e1 * 80}px) scale(${1 + e1 * 0.1}) rotateX(${-e1 * 14}deg)`;
        hero.style.opacity   = String(Math.max(1 - e1 * 1.7, 0));
        hero.style.filter    = `blur(${e1 * 22}px)`;
        bg.style.transform   = `scale(${1 + e1 * 0.07})`;
        if (overlay) overlay.style.opacity = String(0.15 + e1 * 0.55);

        // Phase 2 (0.08→0.7): card rises
        const p2  = Math.min(Math.max((p - 0.08) / 0.62, 0), 1);
        const e2  = 1 - Math.pow(1 - p2, 4);
        const cardY = (1 - e2) * (vh + 400);
        const tilt  = (1 - e2) * 4;
        card.style.transform = `translateY(${cardY}px) rotateX(${tilt}deg)`;
        p2Ref.current = p2;

        // Iframe zoom-in effect: scale goes 1.15→1, blur goes 6px→0 as card rises
        // At p2=0 → scale(1.15) blur(6px); at p2=1 → scale(1) blur(0)
        if (iframe && !snapFullscreenRef.current) {
          const iframeScale = 1.15 - 0.15 * e2;
          const iframeBlur  = 6 * (1 - e2);
          iframe.style.transform = `scale(${iframeScale})`;
          iframe.style.filter    = `blur(${iframeBlur}px)`;

          // Mirror border-radius on iframe wrap (28px → 0 at fullscreen, but during scroll mirror card)
          const br = 28 * (1 - e2);
          if (iframeWrapRef.current && !snapFullscreenRef.current) {
            iframeWrapRef.current.style.borderRadius = `${br}px`;
          }
        }

        // Snap to fullscreen when card is sufficiently risen
        if (p2 > 0.6 && !snapFullscreenRef.current) {
          snapToFullscreen();
        }
      });
    };

    root.addEventListener('scroll', onScroll, { passive: true });
    return () => { root.removeEventListener('scroll', onScroll); cancelAnimationFrame(rafRef.current); };
  }, []);

  return (
    <>
      <style dangerouslySetInnerHTML={{ __html: CSS }} />

      <button className="ci-skip" onClick={triggerExit}>Pular →</button>

      <div ref={rootRef} className="ci-root">
        <div className="ci-track">
          <div className="ci-sticky">
            {/* Background layers */}
            <div ref={bgRef} className="ci-bg" aria-hidden="true" />
            <div ref={overlayRef} className="ci-bg-overlay" aria-hidden="true" />
            <div className="ci-vignette" aria-hidden="true" />
            <div className="ci-grain" aria-hidden="true" />
            <div className="ci-scanlines" aria-hidden="true" />
            <div className="ci-streak" aria-hidden="true" />

            {/* Corner accents */}
            <div className="ci-corner ci-corner--tl" aria-hidden="true" />
            <div className="ci-corner ci-corner--tr" aria-hidden="true" />
            <div className="ci-corner ci-corner--bl" aria-hidden="true" />
            <div className="ci-corner ci-corner--br" aria-hidden="true" />

            {/* Hero text */}
            <div ref={heroRef} className="ci-hero-wrap">
              <div className="ci-headline">
                <h1 className="ci-line1">
                  <span className="ci-line1-inner">
                    {/* FERRAMENTAS — char by char */}
                    {'FERRAMENTAS'.split('').map((ch, i) => (
                      <span
                        key={`w1-${i}`}
                        className="ci-char ci-word-navy"
                        style={{ animationDelay: `${0.08 + i * 0.045}s` }}
                      >{ch}</span>
                    ))}
                    <span className="ci-char-space" />
                    {/* QUE — char by char, offset after FERRAMENTAS */}
                    {'QUE'.split('').map((ch, i) => (
                      <span
                        key={`w2-${i}`}
                        className="ci-char ci-word-white"
                        style={{ animationDelay: `${0.08 + 11 * 0.045 + 0.06 + i * 0.055}s` }}
                      >{ch}</span>
                    ))}
                  </span>
                </h1>
                <h2 className="ci-line2">
                  <span className="ci-line2-inner">FAZEM A DIFERENÇA</span>
                </h2>
                <div className="ci-divider">
                  <div className="ci-div-white" />
                  <div className="ci-div-navy" />
                </div>
                <p className="ci-tagline">SMB Máquinas · Poder que move profissionais</p>
              </div>
              <div className="ci-hint">
                <div className="ci-hint-line" />
                <span>Role para entrar</span>
                <div className="ci-hint-arrow" />
              </div>
            </div>

            {/* Card */}
            <div ref={cardRef} className="ci-card">
              {/* Orange background mesh — fades when iframe loads */}
              <div ref={meshRef} className="ci-card-mesh" aria-hidden="true" />
              <div ref={noiseRef} className="ci-card-noise" aria-hidden="true" />
              <div ref={topRef} className="ci-card-top" aria-hidden="true" />
              <div ref={accentRef} className="ci-card-accent" aria-hidden="true" />

              {/* Loading spinner — visible until iframe onLoad */}
              <div ref={spinnerRef} className="ci-card-spinner" aria-hidden="true">
                <div className="ci-spinner-ring" />
              </div>

              {/* Iframe — loads site in background, zoomed + blurred until near-fullscreen */}
              <div ref={iframeWrapRef} className="ci-card-iframe-wrap">
                <iframe
                  ref={iframeRef}
                  src={iframeUrl}
                  className="ci-card-iframe"
                  title="Site preview"
                  onLoad={handleIframeLoad}
                  // Security: same-origin only (window.location.href is always same-origin)
                  sandbox="allow-same-origin allow-scripts allow-forms allow-popups"
                />
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}